import static org.junit.jupiter.api.Assertions.*;

public class Parser_parseInput_0_Test {

    /**
     * A stub TreeBuilder that returns a sentinel Document or throws exceptions as configured.
     */
    private static class FakeTreeBuilder extends TreeBuilder {
        private final Document toReturn;
        private final RuntimeException toThrow;

        FakeTreeBuilder(Document toReturn) {
            this.toReturn = toReturn;
            this.toThrow = null;
        }

        FakeTreeBuilder(RuntimeException toThrow) {
            this.toReturn = null;
            this.toThrow = toThrow;
        }

        @Override
        public Document parse(Reader input, String baseUri, Parser parser) {
            if (toThrow != null) {
                throw toThrow;
            }
            return toReturn;
        }

        @Override public TreeBuilder newInstance() { return new FakeTreeBuilder(toReturn != null ? toReturn : toThrow); }
        @Override public org.jsoup.parser.ParseSettings defaultSettings() { return org.jsoup.parser.ParseSettings.htmlDefault; }
        @Override public java.util.List<org.jsoup.nodes.Node> parseFragment(Reader input, org.jsoup.nodes.Element context, String baseUri, Parser parser) {
            throw new UnsupportedOperationException();
        }
        @Override public boolean isContentForTagData(String normalName) { return false; }
        @Override public String defaultNamespace() { return ""; }
        @Override public void initialiseParse(Reader input, String baseUri, Parser parser) { /* no-op */ }

        // Implementing the abstract method from TreeBuilder
        @Override public void process(org.jsoup.parser.Token token) { /* no-op */ }
    }

    @Test
    @DisplayName("TC01_O1: parseInput(String, String) with non-empty HTML and non-null baseUri invokes treeBuilder.parse and returns Document")
    public void test_TC01_O1() {
        Document sentinel = new Document("http://example.com");
        FakeTreeBuilder stub = new FakeTreeBuilder(sentinel);
        Parser parser = new Parser(stub);
        String html = "<p>text</p>";
        String baseUri = "http://example.com";

        Document result = parser.parseInput(html, baseUri);

        assertEquals(sentinel, result, "Expected the sentinel Document from FakeTreeBuilder.parse");
    }

    @Test
    @DisplayName("TC02_O1: parseInput(String, String) with empty HTML string and non-null baseUri returns Document")
    public void test_TC02_O1() {
        Document sentinel = new Document("http://example.com");
        FakeTreeBuilder stub = new FakeTreeBuilder(sentinel);
        Parser parser = new Parser(stub);
        String html = "";
        String baseUri = "http://example.com";

        Document result = parser.parseInput(html, baseUri);

        assertEquals(sentinel, result, "Expected the sentinel Document even for empty HTML input");
    }

    @Test
    @DisplayName("TC03_O1: parseInput(String, String) with null html throws NullPointerException")
    public void test_TC03_O1() {
        Parser parser = new Parser(new FakeTreeBuilder(new Document("u")));
        String html = null;
        String baseUri = "http://example.com";

        assertThrows(NullPointerException.class, () -> parser.parseInput(html, baseUri),
                "Expected NullPointerException when html is null");
    }

