    @Test
    @DisplayName("TC07_O2: parseInput(Reader, String) with null Reader throws NullPointerException")
    public void test_TC07_O2() {
        Parser parser = new Parser(new FakeTreeBuilder(new Document("u")));
        Reader reader = null;
        String baseUri = "uri";

        assertThrows(NullPointerException.class, () -> parser.parseInput(reader, baseUri),
                "Expected NullPointerException when reader is null");
    }

    @Test
    @DisplayName("TC08_O2: parseInput(Reader, String) with null baseUri throws NullPointerException")
    public void test_TC08_O2() {
        Document sentinel = new Document("dummy");
        FakeTreeBuilder stub = new FakeTreeBuilder(sentinel);
        Parser parser = new Parser(stub);
        Reader reader = new StringReader("x");
        String baseUri = null;

        assertThrows(NullPointerException.class, () -> parser.parseInput(reader, baseUri),
                "Expected NullPointerException when baseUri is null for Reader overload");
    }

    @Test
    @DisplayName("TC09_O1: parseInput(String, String) propagates exception thrown by treeBuilder.parse")
    public void test_TC09_O1() {
        FakeTreeBuilder stub = new FakeTreeBuilder(new IllegalStateException("parse failed"));
        Parser parser = new Parser(stub);
        String html = "<a>";
        String baseUri = "u";

        IllegalStateException ex = assertThrows(IllegalStateException.class,
                () -> parser.parseInput(html, baseUri),
                "Expected IllegalStateException propagated from treeBuilder.parse");
        assertEquals("parse failed", ex.getMessage());
    }

    @Test
    @DisplayName("TC10_O2: parseInput(Reader, String) propagates exception thrown by treeBuilder.parse")
    public void test_TC10_O2() {
        FakeTreeBuilder stub = new FakeTreeBuilder(new IllegalArgumentException("err"));
        Parser parser = new Parser(stub);
        Reader reader = new StringReader("<b>");
        String baseUri = "u";

        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class,
                () -> parser.parseInput(reader, baseUri),
                "Expected IllegalArgumentException propagated from treeBuilder.parse");
        assertEquals("err", ex.getMessage());
    }
}
